import React, { Fragment } from 'react'
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableContainer from '@material-ui/core/TableContainer';
import TableHead from '@material-ui/core/TableHead';
import TableRow from '@material-ui/core/TableRow';
import { withStyles, Theme, createStyles } from '@material-ui/core/styles';
import Paper from '@material-ui/core/Paper';
import Box from '@material-ui/core/Box';

interface ListControlProps {
    columns: Array<any>,
    rows: Array<any>,
    headerColor?: string,
    oddRowColor?: string,
    evenRowColor?: string,
    onRowClickHandler:any,
    height:number,
    field:string
}

const ListControl: React.FC<ListControlProps> = (props: ListControlProps) => {

    
    const StyledTableCell = withStyles((theme: Theme) =>
        createStyles({
            head: {
                backgroundColor: props.headerColor || "rgb(204,204,204)",
                color: theme.palette.common.black,
            },
            body: {
                fontSize: 14,
            }
        }),
    )(TableCell);

    const StyledTableRow = withStyles((theme: Theme) =>
        createStyles({
            root: {
                '&:nth-of-type(odd)': {
                    backgroundColor: props.oddRowColor || theme.palette.action.hover,
                },
                '&:nth-of-type(even)': {
                    backgroundColor: props.evenRowColor || theme.palette.common.white,
                },
            },
        }),
    )(TableRow);



    return <Fragment>
        <Box display={{ xs: 'block', md: 'none' }}>
            <TableContainer style={{height:300,overflow:"auto"}} component={Paper}>
                <Table>
                    <TableBody>
                        {props.rows.map((row) => <StyledTableRow key={row.name}>
                            {Object.keys(row).map((key,index) =>key!="idd"?<div style={{width:"100%"}} ><StyledTableCell align="left"><b>{props.columns[index]}</b>:{row[key]}</StyledTableCell></div>:null)}
                        </StyledTableRow>)
                        }
                    </TableBody>
                </Table>
            </TableContainer>
        </Box>
        <Box display={{ xs: 'none', md: 'block' }}>
            <TableContainer style={{maxHeight:300,overflow:"auto"}} component={Paper}>
                <Table  stickyHeader>
                    <TableHead style={{display:props.columns.length?'block':'none'}}>
                        <TableRow>
                            {
                                props.columns.map(col => col!="idd"?<StyledTableCell>{col} </StyledTableCell>:null)
                            }
                        </TableRow>
                    </TableHead>
                   
                    <TableBody >
                        {props.rows.map((row,index) => (
                            <StyledTableRow key={row.name} onClick={(event:any)=>props.onRowClickHandler(event,row[props.field],index)}>

                                {
                                    Object.keys(row).map(key =>key!="idd"?<StyledTableCell align="left">{row[key]}</StyledTableCell>:null)
                                }
                            </StyledTableRow>
                        ))}
                    </TableBody>
                </Table>
            </TableContainer>
        </Box>
    </Fragment>
}

export default ListControl