import React, { useEffect } from 'react'
import List from './List'
import {connect} from 'react-redux'
import { FETCH_PATIENTS_DATA } from './actions'


const mapStateToProps=(state:any)=>{
    return {
      patients:state.duplicatePatients || []
    }
}

const mapDispatchToProps=(dispatch:any)=>{
    return {
        
        fetchPatientData:(id:any)=>{
            dispatch({
                type:FETCH_PATIENTS_DATA,
                payload:id
            })
        }
    }
}

const PatientsComp= ({patients,fetchPatientData}:any) => {
    let lastElement:any=null
    
    const RowClickHandler=(event:any,id:any,index:any)=>{
        
        
        fetchPatientData(id)

        event.target.parentElement.style.background="lightGrey"
        if(lastElement)
        {
            lastElement.parentElement.style.background=index%2?"rgba(0, 0, 0, 0.04)":"white"
        }
        lastElement=event.target;
    }


    return <div>
        <header className={"patientsHeader"}>Duplicate Patients</header>
       {patients.length?<List oddRowColor={"#F4F4FF"} evenRowColor={"#F4F4FF"} field="id" columns={[]} height={300} onRowClickHandler={RowClickHandler} rows={patients} />:null} </div>
}


export default connect(mapStateToProps,mapDispatchToProps)(PatientsComp)

