import React, { useEffect } from 'react'
import List from './List'
import {connect} from 'react-redux'
import {FETCH_DUPLICATE_PATIENTS, FETCH_PATIENTS} from './actions'

const mapStateToProps=(state:any)=>{
    return {
      patients:state.patients || []
    }
}

const mapDispatchToProps=(dispatch:any)=>{
    return {
        fetchPatients:()=>{
            dispatch({
                type:FETCH_PATIENTS
            })
        },
        fetchDuplicatePatients:(patientId:any)=>{
            dispatch({
                type:FETCH_DUPLICATE_PATIENTS,
                payload:patientId
            })
        }
    }
}


const PatientsComp= ({patients,fetchPatients,fetchDuplicatePatients}:any) => {

    
    let lastElement:any=null
    
    const RowClickHandler=(event:any,name:any,index:any)=>{
        
        
        fetchDuplicatePatients(name)

        event.target.parentElement.style.background="lightGrey"
        if(lastElement)
        {
            lastElement.parentElement.style.background=index%2?"rgba(0, 0, 0, 0.04)":"white"
        }
        lastElement=event.target;
    }

    useEffect(()=>{
     fetchPatients()
    },[])

    return <div>
        <header className={"patientsHeader"}>Patients</header>
         <List  field="details" columns={[]} height={300} onRowClickHandler={RowClickHandler} rows={patients} oddRowColor={"#F4F4FF"} evenRowColor={"#F4F4FF"} /> </div>
}


export default connect(mapStateToProps,mapDispatchToProps)(PatientsComp)

