import React, { useEffect } from 'react'
import { connect } from 'react-redux'
import { FETCH_PATIENTS_DATA } from './actions'


const mapStateToProps = (state: any) => {
    return {
        patient: state.selectedPatient
    }
}

const mapDispatchToProps = (dispatch: any) => {
    return {
    }
}

const PatientsComp = ({ patient }: any) => {

    

    return <div>
        <header className={"patientsHeader"}>Patient Details</header>

        {patient ? <div className="detailsContainer">
            {
                Object.keys(patient).map(key => <div className="detailsRow"><span>{key}</span><span>{patient[key]}</span>   </div>)
            }
        </div> : null}
    </div>
}


export default connect(mapStateToProps, mapDispatchToProps)(PatientsComp)

