import { FETCH_PATIENTS,FETCH_DUPLICATE_PATIENTS,FETCH_PATIENTS_DATA } from './actions'
import data from './data.json'
export default (state: any = {patients:[],duplicatePatients:[]}, action: any) => {
    if (action.type === FETCH_PATIENTS) {
        return {
            ...state, patients: data.patients.map(el => {
                return {
                    id: el.id,
                    details: `${el.name} (${el.birthDate})`
                }
            })
        }
    }
    
    if(action.type===FETCH_DUPLICATE_PATIENTS)
    {
        
        let name =action.payload

        return {
            ...state,duplicatePatients:data.patients.filter(el=>el.name[0]===name[0])
        }
    }

    
    if(action.type===FETCH_PATIENTS_DATA)
    {
        let id =action.payload

        return {
            ...state,selectedPatient:data.patients.find(el=>el.id===id)
        }
    }

    
    
    if(action.type===FETCH_PATIENTS_DATA)
    {
        let id =action.payload

        return {
            ...state,duplicatePatients:data.patients.filter(el=>el.id===id)
        }
    }

    return state;   
}